// Node 2: Data Transformation
// Parse and structure incoming form data from webhook

const body = $input.first().json.body || $input.first().json;

// Helper: safely get value with fallback
const get = (obj, path, fallback = null) => {
  return path.split('.').reduce((acc, key) => (acc && acc[key] !== undefined ? acc[key] : fallback), obj);
};

// Helper: parse time string to HH:MM
const parseTime = (t) => {
  if (!t) return null;
  if (typeof t === 'string' && /^\d{2}:\d{2}$/.test(t)) return t;
  const d = new Date(t);
  if (!isNaN(d)) return d.toTimeString().slice(0, 5);
  return t;
};

// Build lectures array
const lectures = [];
const days = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday'];
days.forEach(day => {
  const dayKey = day.toLowerCase();
  const dayLectures = get(body, `schedule.${dayKey}`, []);
  if (Array.isArray(dayLectures)) {
    dayLectures.forEach(lec => {
      if (lec && lec.name) {
        lectures.push({
          day,
          name: lec.name,
          start: parseTime(lec.start),
          end: parseTime(lec.end),
          location: lec.location || '',
          mandatory: lec.mandatory !== false
        });
      }
    });
  }
});

// Build hobbies array
const hobbies = (get(body, 'hobbies', []) || []).slice(0, 10).map(h => ({
  name: h.name || '',
  days: Array.isArray(h.days) ? h.days : [],
  timeOfDay: h.timeOfDay || 'afternoon',
  duration: parseInt(h.duration) || 60,
  frequency: parseInt(h.frequency) || 1,
  flexible: h.flexible !== false
}));

// Build sports array
const sports = (get(body, 'sports', []) || []).map(s => ({
  type: s.type || '',
  days: Array.isArray(s.days) ? s.days : [],
  startTime: parseTime(s.startTime),
  duration: parseInt(s.duration) || 60,
  location: s.location || '',
  teamCommitment: s.teamCommitment === true || s.teamCommitment === 'true'
}));

// Build social events
const socialEvents = (get(body, 'socialEvents', []) || []).map(e => ({
  eventType: e.eventType || 'Other',
  name: e.name || '',
  days: Array.isArray(e.days) ? e.days : [],
  timeCommitment: parseFloat(e.timeCommitment) || 1,
  recurring: e.recurring === true || e.recurring === 'true'
}));

// Build college events
const collegeEvents = (get(body, 'collegeEvents', []) || []).map(e => ({
  name: e.name || '',
  eventType: e.eventType || 'Other',
  frequency: e.frequency || 'One-time',
  date: e.date || null,
  dayOfWeek: e.dayOfWeek || null,
  duration: parseFloat(e.duration) || 1
}));

// Build deadlines
const deadlines = (get(body, 'deadlines', []) || []).map(d => ({
  name: d.name || '',
  dueDate: d.dueDate || null,
  prepTime: parseFloat(d.prepTime) || 2,
  priority: d.priority || 'Medium'
}));

// Build commute
const commute = {
  location: get(body, 'commute.location', ''),
  mode: get(body, 'commute.mode', 'Bus'),
  toCampus: parseInt(get(body, 'commute.toCampus', 30)),
  fromCampus: parseInt(get(body, 'commute.fromCampus', 30)),
  days: get(body, 'commute.days', ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday'])
};

// Structured output
const structured = {
  student: {
    name: get(body, 'student.name', get(body, 'name', '')),
    email: get(body, 'student.email', get(body, 'email', '')),
    university: get(body, 'student.university', get(body, 'university', '')),
    course: get(body, 'student.course', get(body, 'course', '')),
    year: get(body, 'student.year', get(body, 'year', ''))
  },
  schedule: {
    lectures,
    hobbies,
    sports,
    socialEvents,
    collegeEvents,
    commute,
    deadlines
  },
  routines: {
    wakeTime: parseTime(get(body, 'routines.wakeTime', '07:00')),
    bedTime: parseTime(get(body, 'routines.bedTime', '23:00')),
    morningDuration: parseInt(get(body, 'routines.morningDuration', 60)),
    eveningDuration: parseInt(get(body, 'routines.eveningDuration', 45)),
    personalCare: parseInt(get(body, 'routines.personalCare', 30)),
    mealPrep: parseInt(get(body, 'routines.mealPrep', 60)),
    morningActivities: get(body, 'routines.morningActivities', []),
    eveningActivities: get(body, 'routines.eveningActivities', [])
  },
  work: {
    isWorking: get(body, 'work.isWorking', false),
    hoursPerWeek: parseInt(get(body, 'work.hoursPerWeek', 0)),
    shiftDays: get(body, 'work.shiftDays', []),
    shiftTimes: get(body, 'work.shiftTimes', ''),
    isJobHunting: get(body, 'work.isJobHunting', false),
    jobHuntingHours: parseInt(get(body, 'work.jobHuntingHours', 0)),
    preferredJobHuntTime: get(body, 'work.preferredJobHuntTime', ''),
    interviews: get(body, 'work.interviews', [])
  },
  goals: {
    mainGoals: get(body, 'goals.mainGoals', ''),
    strengths: get(body, 'goals.strengths', ''),
    weaknesses: get(body, 'goals.weaknesses', ''),
    improvements: get(body, 'goals.improvements', ''),
    scheduleObjectives: get(body, 'goals.scheduleObjectives', []),
    additionalContext: get(body, 'goals.additionalContext', '')
  },
  preferences: {
    studyHoursWeekly: parseInt(get(body, 'preferences.studyHoursWeekly', 15)),
    idealStudyHours: parseInt(get(body, 'preferences.idealStudyHours', 20)),
    studyStyle: get(body, 'preferences.studyStyle', 'long_blocks'),
    studyLocation: get(body, 'preferences.studyLocation', 'library'),
    bestStudyTime: get(body, 'preferences.bestStudyTime', ['morning']),
    breakDuration: parseInt(get(body, 'preferences.breakDuration', 30)),
    downtimeDaily: parseFloat(get(body, 'preferences.downtimeDaily', 2)),
    maxHoursPerDay: parseInt(get(body, 'preferences.maxHoursPerDay', 14)),
    freeDays: get(body, 'preferences.freeDays', ['Sunday']),
    energyLevels: get(body, 'preferences.energyLevels', 'morning'),
    afternoonNap: get(body, 'preferences.afternoonNap', false)
  }
};

// Validation: check required fields
const missing = [];
if (!structured.student.name) missing.push('name');
if (!structured.student.email) missing.push('email');
if (!structured.routines.wakeTime) missing.push('wakeTime');
if (!structured.routines.bedTime) missing.push('bedTime');

if (missing.length > 0) {
  throw new Error(`VALIDATION_FAILED: Missing required fields: ${missing.join(', ')}`);
}

return [{ json: structured }];

// Node 8: Build Claude API Prompt
const data = $node['Transform Data'].json;
const { student, schedule, routines, work, goals, preferences } = data;

// Format lectures section
const formatLectures = (lectures) => {
  if (!lectures || lectures.length === 0) return 'No lectures provided.';
  return lectures.map(l =>
    `- ${l.day}: ${l.name} (${l.start}-${l.end})${l.location ? ` at ${l.location}` : ''} [Mandatory: ${l.mandatory}]`
  ).join('\n');
};

// Format hobbies section
const formatHobbies = (hobbies) => {
  if (!hobbies || hobbies.length === 0) return 'No hobbies listed.';
  return hobbies.map(h =>
    `- ${h.name}: ${h.frequency}x per week on ${h.days.join(', ')}, ${h.duration} min/session [Flexible: ${h.flexible}]`
  ).join('\n');
};

// Format sports section
const formatSports = (sports) => {
  if (!sports || sports.length === 0) return 'No sports listed.';
  return sports.map(s =>
    `- ${s.type} on ${s.days.join(', ')} at ${s.startTime} for ${s.duration} min [Team: ${s.teamCommitment}]`
  ).join('\n');
};

// Format social events
const formatSocialEvents = (events) => {
  if (!events || events.length === 0) return 'No social events.';
  return events.map(e =>
    `- ${e.eventType}: ${e.name} (${e.timeCommitment} hrs/week) [Recurring: ${e.recurring}]`
  ).join('\n');
};

// Format college events
const formatCollegeEvents = (events) => {
  if (!events || events.length === 0) return 'No college events.';
  return events.map(e =>
    `- ${e.name} (${e.eventType}): ${e.frequency}, ${e.duration} hrs`
  ).join('\n');
};

// Format deadlines
const formatDeadlines = (deadlines) => {
  if (!deadlines || deadlines.length === 0) return 'No upcoming deadlines.';
  return deadlines.map(d =>
    `- ${d.name}: Due ${d.dueDate}, needs ${d.prepTime} hrs [Priority: ${d.priority}]`
  ).join('\n');
};

// Format work section
const formatWork = (work) => {
  if (!work || !work.isWorking) return 'Not currently working part-time.';
  let txt = `Part-time work: ${work.hoursPerWeek} hrs/week on ${work.shiftDays.join(', ')} (${work.shiftTimes})`;
  if (work.isJobHunting) {
    txt += `\nJob hunting: ${work.jobHuntingHours} hrs/week (preferred: ${work.preferredJobHuntTime})`;
  }
  if (work.interviews && work.interviews.length > 0) {
    txt += `\nScheduled interviews: ${work.interviews.map(i => `${i.date} at ${i.time}`).join(', ')}`;
  }
  return txt;
};

const prompt = `You are an expert schedule optimization consultant for Irish university students. A student has provided comprehensive information about their commitments, goals, and preferences. Your task is to create a personalized, optimized weekly schedule.

# STUDENT PROFILE

**Name:** ${student.name}
**University:** ${student.university}
**Course:** ${student.course}
**Year:** ${student.year}

# TIME CONSTRAINTS

**Wake Time:** ${routines.wakeTime}
**Bed Time:** ${routines.bedTime}
**Morning Routine Duration:** ${routines.morningDuration} minutes
**Evening Routine Duration:** ${routines.eveningDuration} minutes
**Daily Personal Care:** ${routines.personalCare} minutes
**Meal Preparation:** ${routines.mealPrep} minutes per day

# FIXED COMMITMENTS

## Lectures/Classes
${formatLectures(schedule.lectures)}

## Commute
- **Home Location:** ${schedule.commute.location || 'Not specified'}
- **Transport:** ${schedule.commute.mode}
- **To Campus:** ${schedule.commute.toCampus} minutes
- **From Campus:** ${schedule.commute.fromCampus} minutes
- **Days:** ${Array.isArray(schedule.commute.days) ? schedule.commute.days.join(', ') : schedule.commute.days}

## Sports & Fitness
${formatSports(schedule.sports)}

## Hobbies & Activities
${formatHobbies(schedule.hobbies)}

## Social & College Events
${formatSocialEvents(schedule.socialEvents)}
${formatCollegeEvents(schedule.collegeEvents)}

## Work & Employment
${formatWork(work)}

# STUDY REQUIREMENTS

- **Current Study Hours/Week:** ${preferences.studyHoursWeekly}
- **Target Study Hours/Week:** ${preferences.idealStudyHours}
- **Study Style Preference:** ${preferences.studyStyle}
- **Best Study Times:** ${Array.isArray(preferences.bestStudyTime) ? preferences.bestStudyTime.join(', ') : preferences.bestStudyTime}
- **Study Location:** ${preferences.studyLocation}

## Upcoming Deadlines
${formatDeadlines(schedule.deadlines)}

# STUDENT GOALS & SELF-ASSESSMENT

**Main Goals This Semester:** ${goals.mainGoals}

**Natural Strengths:** ${goals.strengths}

**Areas of Struggle:** ${goals.weaknesses}

**Skills/Habits to Improve:** ${goals.improvements}

**What Student Wants from Schedule:**
${Array.isArray(goals.scheduleObjectives) ? goals.scheduleObjectives.map(o => `- ${o}`).join('\n') : goals.scheduleObjectives}

**Additional Context:** ${goals.additionalContext}

# PREFERENCES & CONSTRAINTS

- **Break Duration Between Classes:** ${preferences.breakDuration} minutes
- **Daily Downtime Needed:** ${preferences.downtimeDaily} hours
- **Maximum Scheduled Hours/Day:** ${preferences.maxHoursPerDay}
- **Days to Keep Free:** ${Array.isArray(preferences.freeDays) ? preferences.freeDays.join(', ') : preferences.freeDays}
- **Energy Peaks:** ${preferences.energyLevels}
- **Needs Afternoon Nap/Break:** ${preferences.afternoonNap}

# YOUR TASK

Create an optimized weekly schedule that:

1. **Respects all fixed commitments** (lectures, sports, commute times)
2. **Incorporates study blocks** matching their study style and preferred times
3. **Includes buffer time** for meals, personal care, and transitions
4. **Accounts for their strengths and weaknesses**
5. **Aligns with their goals**
6. **Provides realistic downtime** to prevent burnout
7. **Optimizes for their energy levels**
8. **Builds in deadline preparation** for upcoming assignments/exams

# OUTPUT FORMAT

Return ONLY valid JSON with this exact structure:

{
  "weeklySchedule": {
    "Monday": [
      {
        "time": "07:00-07:30",
        "activity": "Morning Routine",
        "type": "personal|academic|social|fitness|work|downtime",
        "location": "Home",
        "flexible": false,
        "notes": "Optional brief note"
      }
    ],
    "Tuesday": [],
    "Wednesday": [],
    "Thursday": [],
    "Friday": [],
    "Saturday": [],
    "Sunday": []
  },
  "recommendations": {
    "summary": "2-3 sentence overview of the optimized schedule",
    "keyInsights": ["insight1", "insight2", "insight3"],
    "studyStrategy": "Explanation of how study blocks are distributed and why",
    "improvements": ["habit1", "tip2", "suggestion3"],
    "warnings": ["warning1", "concern2"]
  },
  "metrics": {
    "totalScheduledHours": 65,
    "academicHours": 25,
    "studyHours": 20,
    "fitnessHours": 5,
    "socialHours": 8,
    "freeTime": 15,
    "sleepHours": 56,
    "busiestDay": "Wednesday",
    "lightestDay": "Sunday"
  }
}

# IMPORTANT RULES

- Schedule MUST start at wake time and end at bed time
- Include ALL mandatory commitments (lectures, team sports)
- Leave realistic buffer time between activities (minimum 15 minutes for transitions)
- Schedule meals at reasonable times (breakfast after waking, lunch 12-2pm, dinner 6-8pm)
- Don't over-schedule: respect their "maximum hours per day" limit
- Account for commute time before/after campus activities
- Respect their natural energy levels

Now generate the optimized schedule.`;

return [{ json: { prompt } }];

// Node 10: Parse Claude Response
const response = $input.first().json;

// Extract text content from Claude API response
let rawText = '';
if (response.content && Array.isArray(response.content)) {
  rawText = response.content.find(c => c.type === 'text')?.text || '';
} else if (response.choices) {
  // Fallback for OpenAI-style responses
  rawText = response.choices[0]?.message?.content || '';
}

if (!rawText) {
  throw new Error('PARSE_ERROR: No text content in Claude response');
}

// Extract JSON from response (Claude may include markdown code blocks)
let jsonStr = rawText.trim();

// Remove markdown code fences if present
const jsonMatch = jsonStr.match(/```(?:json)?\s*([\s\S]*?)\s*```/);
if (jsonMatch) {
  jsonStr = jsonMatch[1].trim();
}

// Try to find JSON object if there's surrounding text
if (!jsonStr.startsWith('{')) {
  const objStart = jsonStr.indexOf('{');
  const objEnd = jsonStr.lastIndexOf('}');
  if (objStart !== -1 && objEnd !== -1) {
    jsonStr = jsonStr.slice(objStart, objEnd + 1);
  }
}

let parsed;
try {
  parsed = JSON.parse(jsonStr);
} catch (e) {
  throw new Error(`PARSE_ERROR: Failed to parse JSON from Claude: ${e.message}`);
}

// Validate required structure
if (!parsed.weeklySchedule) {
  throw new Error('PARSE_ERROR: Missing weeklySchedule in Claude response');
}
if (!parsed.recommendations) {
  throw new Error('PARSE_ERROR: Missing recommendations in Claude response');
}
if (!parsed.metrics) {
  throw new Error('PARSE_ERROR: Missing metrics in Claude response');
}

// Merge with student data
const studentData = $node['Transform Data'].json;

return [{
  json: {
    student: studentData.student,
    schedule_id: $node['Insert Schedule Data'].json.id,
    weeklySchedule: parsed.weeklySchedule,
    recommendations: parsed.recommendations,
    metrics: parsed.metrics,
    rawPromptTokens: response.usage?.input_tokens || 0,
    rawCompletionTokens: response.usage?.output_tokens || 0
  }
}];

// Node 12: Format Email HTML
const data = $input.first().json;
const { student, weeklySchedule, recommendations, metrics } = data;

const days = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday', 'Sunday'];

// Color map for activity types
const typeColors = {
  academic: '#4A90D9',
  personal: '#7ED321',
  fitness: '#F5A623',
  social: '#9B59B6',
  work: '#E74C3C',
  downtime: '#95A5A6',
  default: '#BDC3C7'
};

// Build schedule table HTML
const buildScheduleTable = () => {
  let html = `
  <table style="width:100%;border-collapse:collapse;margin:20px 0;font-family:Arial,sans-serif;font-size:13px;">
    <thead>
      <tr style="background:#2C3E50;color:white;">
        <th style="padding:10px;text-align:left;width:80px;">Time</th>
        ${days.map(d => `<th style="padding:10px;text-align:center;">${d.slice(0,3)}</th>`).join('')}
      </tr>
    </thead>
    <tbody>
  `;

  // Collect all unique time slots across all days
  const allTimes = new Set();
  days.forEach(day => {
    (weeklySchedule[day] || []).forEach(slot => {
      allTimes.add(slot.time.split('-')[0]);
    });
  });

  const sortedTimes = Array.from(allTimes).sort();

  // Build a lookup map for quick access
  const slotMap = {};
  days.forEach(day => {
    slotMap[day] = {};
    (weeklySchedule[day] || []).forEach(slot => {
      const startTime = slot.time.split('-')[0];
      slotMap[day][startTime] = slot;
    });
  });

  sortedTimes.forEach((time, i) => {
    const bgColor = i % 2 === 0 ? '#f9f9f9' : '#ffffff';
    html += `<tr style="background:${bgColor};">`;
    html += `<td style="padding:8px;font-weight:bold;color:#555;white-space:nowrap;">${time}</td>`;
    days.forEach(day => {
      const slot = slotMap[day][time];
      if (slot) {
        const color = typeColors[slot.type] || typeColors.default;
        html += `<td style="padding:6px;text-align:center;">
          <div style="background:${color};color:white;border-radius:4px;padding:4px 6px;font-size:11px;">
            ${slot.activity}${slot.location ? '<br><small style="opacity:0.85">📍 '+slot.location+'</small>' : ''}
          </div>
        </td>`;
      } else {
        html += '<td></td>';
      }
    });
    html += '</tr>';
  });

  html += '</tbody></table>';
  return html;
};

// Build metrics cards
const buildMetrics = () => {
  const cards = [
    { label: 'Academic Hours', value: metrics.academicHours + 'h', color: '#4A90D9' },
    { label: 'Study Hours', value: metrics.studyHours + 'h', color: '#27AE60' },
    { label: 'Free Time', value: metrics.freeTime + 'h', color: '#F39C12' },
    { label: 'Sleep Hours', value: metrics.sleepHours + 'h', color: '#8E44AD' },
    { label: 'Fitness Hours', value: metrics.fitnessHours + 'h', color: '#E74C3C' },
    { label: 'Busiest Day', value: metrics.busiestDay, color: '#2C3E50' }
  ];

  return `<div style="display:flex;flex-wrap:wrap;gap:12px;margin:20px 0;">
    ${cards.map(c => `
      <div style="background:${c.color};color:white;border-radius:8px;padding:12px 16px;min-width:120px;text-align:center;">
        <div style="font-size:24px;font-weight:bold;">${c.value}</div>
        <div style="font-size:12px;opacity:0.9;margin-top:4px;">${c.label}</div>
      </div>`).join('')}
  </div>`;
};

// Build recommendations section
const buildRecommendations = () => {
  const { summary, keyInsights, studyStrategy, improvements, warnings } = recommendations;
  return `
  <div style="background:#EBF5FB;border-left:4px solid #4A90D9;padding:16px;margin:16px 0;border-radius:0 8px 8px 0;">
    <h3 style="margin:0 0 8px;color:#2C3E50;">Schedule Overview</h3>
    <p style="margin:0;color:#555;">${summary}</p>
  </div>

  <h3 style="color:#2C3E50;">Key Insights</h3>
  <ul style="color:#555;line-height:1.8;">
    ${(keyInsights || []).map(i => `<li>${i}</li>`).join('')}
  </ul>

  <h3 style="color:#2C3E50;">Study Strategy</h3>
  <p style="color:#555;">${studyStrategy}</p>

  <h3 style="color:#2C3E50;">Recommendations</h3>
  <ul style="color:#555;line-height:1.8;">
    ${(improvements || []).map(i => `<li>✅ ${i}</li>`).join('')}
  </ul>

  ${warnings && warnings.length > 0 ? `
  <h3 style="color:#E74C3C;">⚠️ Heads Up</h3>
  <ul style="color:#E74C3C;line-height:1.8;">
    ${warnings.map(w => `<li>${w}</li>`).join('')}
  </ul>` : ''}
  `;
};

const html = `
<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Your Personalized Schedule — UniBluePrint</title>
</head>
<body style="font-family:Arial,sans-serif;background:#f4f6f8;margin:0;padding:0;">
  <div style="max-width:800px;margin:0 auto;background:white;">
    <!-- Header -->
    <div style="background:linear-gradient(135deg,#1a237e,#283593);color:white;padding:40px 32px;">
      <h1 style="margin:0;font-size:28px;">Your Personalized Weekly Schedule</h1>
      <p style="margin:8px 0 0;opacity:0.85;font-size:16px;">Prepared exclusively for ${student.name}</p>
      <p style="margin:4px 0 0;opacity:0.7;font-size:14px;">${student.university} · ${student.course} · Year ${student.year}</p>
    </div>

    <!-- Body -->
    <div style="padding:32px;">
      <p style="color:#555;font-size:15px;">Hi ${student.name.split(' ')[0]},</p>
      <p style="color:#555;font-size:15px;">Your optimized weekly schedule is ready! We've analyzed your commitments, goals, and preferences to create a schedule that works best for you.</p>

      <h2 style="color:#1a237e;">📊 Your Week at a Glance</h2>
      ${buildMetrics()}

      <h2 style="color:#1a237e;">📅 Weekly Schedule</h2>
      <p style="color:#777;font-size:13px;">Scroll right on mobile to see the full schedule.</p>
      <div style="overflow-x:auto;">
        ${buildScheduleTable()}
      </div>

      <!-- Legend -->
      <div style="margin:16px 0;display:flex;flex-wrap:wrap;gap:10px;">
        ${Object.entries(typeColors).filter(([k]) => k !== 'default').map(([type, color]) =>
          `<span style="background:${color};color:white;padding:4px 10px;border-radius:12px;font-size:12px;text-transform:capitalize;">${type}</span>`
        ).join('')}
      </div>

      <h2 style="color:#1a237e;">💡 Your Personalized Recommendations</h2>
      ${buildRecommendations()}

      <!-- Next Steps -->
      <div style="background:#F0FFF4;border:1px solid #A8D5B5;border-radius:8px;padding:20px;margin:24px 0;">
        <h3 style="margin:0 0 12px;color:#2D6A4F;">🚀 Next Steps</h3>
        <ol style="color:#555;line-height:2;margin:0;padding-left:20px;">
          <li>Save this schedule to your calendar (sync coming soon!)</li>
          <li>Set reminders for your study blocks</li>
          <li>Review your schedule weekly and adjust as needed</li>
          <li>Reach out to us if you need a schedule revision</li>
        </ol>
      </div>

      <p style="color:#555;">Best of luck this semester! 🍀</p>
      <p style="color:#555;"><strong>The UniBluePrint Team</strong></p>
    </div>

    <!-- Footer -->
    <div style="background:#2C3E50;color:#BDC3C7;padding:24px 32px;font-size:12px;">
      <p style="margin:0;">© ${new Date().getFullYear()} UniBluePrint. All rights reserved.</p>
      <p style="margin:8px 0 0;">This schedule was generated using AI. Review and adjust based on your specific needs.</p>
    </div>
  </div>
</body>
</html>`;

return [{ json: { html, student, subject: `Your Personalized Schedule is Ready, ${student.name.split(' ')[0]}! 🎓` } }];

// Error Handler: Validation Failed
const errorMessage = $input.first().json.error?.message || 'Unknown validation error';
const isValidationError = errorMessage.includes('VALIDATION_FAILED');

if (!isValidationError) {
  // Re-throw non-validation errors
  throw new Error(errorMessage);
}

// Extract student email if available
const body = $node['Webhook Trigger']?.json?.body || {};
const email = body.email || body['student.email'] || '';
const name = body.name || body['student.name'] || 'Student';

return [{ json: { email, name, errorMessage, type: 'validation' } }];
